#include <stdint.h>
#include <stdbool.h>

typedef struct {
  uint8_t data[64];
  uint8_t r;
  uint8_t w;
} Ring;

static Ring rx = {{0}, 0, 0};

static bool ring_push(Ring* rb, uint8_t v) {
  uint8_t nw = (uint8_t)(rb->w + 1);
  if (nw == rb->r) return false;
  rb->data[rb->w] = v;
  rb->w = nw;
  return true;
}

static bool ring_pop(Ring* rb, uint8_t* out) {
  if (rb->r == rb->w) return false;
  *out = rb->data[rb->r];
  rb->r = (uint8_t)(rb->r + 1);
  return true;
}

typedef struct {
  uint32_t ms;
  uint32_t last;
  uint8_t  state;
} Led;

static Led led = {0, 0, 0};

static void gpio_write(uint8_t pin, bool high) {
  (void)pin;
  (void)high;
}

static uint32_t tick_ms(void) {
  led.ms += 1;
  return led.ms;
}

static void led_step(Led* l, uint32_t now) {
  if (now - l->last < 250) return;
  l->last = now;
  l->state ^= 1;
  gpio_write(13, l->state != 0);
}

static uint16_t crc16(const uint8_t* p, uint32_t n) {
  uint16_t c = 0xFFFF;
  for (uint32_t i = 0; i < n; i++) {
    c ^= (uint16_t)p[i] << 8;
    for (uint8_t b = 0; b < 8; b++) {
      c = (c & 0x8000) ? (c << 1) ^ 0x1021 : (c << 1);
    }
  }
  return c;
}

int main(void) {
  (void)ring_push(&rx, 7);
  uint8_t v = 0;
  (void)ring_pop(&rx, &v);
  uint8_t buf[4] = {1, 2, 3, 4};
  uint16_t c = crc16(buf, 4);

  for (;;) {
    uint32_t now = tick_ms();
    (void)c;
    (void)v;
    led_step(&led, now);
  }
}

